#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
int height(TreeNode* node) {
    if (node == NULL) return 0;
    return 1 + max(height(node->left), height(node->right));
}
bool is_balanced(TreeNode* root) {
    if (root == NULL) return true;
    int left_height = height(root->left);
    int right_height = height(root->right);
    return (abs(left_height - right_height) <= 1 &&
            is_balanced(root->left) &&
            is_balanced(root->right));
}
TreeNode* build_tree(vector<int>& nodes) {
    if (nodes.empty()) return NULL;
    TreeNode* root = new TreeNode(nodes[0]);
    queue<TreeNode*> q;
    q.push(root);
    int i = 1;
    while (i < nodes.size()) {
        TreeNode* current_node = q.front(); q.pop();
        if (nodes[i] != -1) {
            current_node->left = new TreeNode(nodes[i]);
            q.push(current_node->left);
        }
        i++;
        if (i < nodes.size() && nodes[i] != -1) {
            current_node->right = new TreeNode(nodes[i]);
            q.push(current_node->right);
        }
        i++;
    }
    return root;
}
int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    TreeNode* root = build_tree(nums);
    cout << (is_balanced(root) ? "true" : "false") << endl;
    return 0;
}
